import{_ as t,o as h,c as i,ag as o}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"[Client / App Specs] Sprint 4: Đặt chỗ & Thanh toán (Checkout UX)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/06-client-app-specs.md","filePath":"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/06-client-app-specs.md"}'),a={name:"05-quan-ly-sprint/sprint-6-dat-cho-thanh-toan/06-client-app-specs.md"};function e(c,n,r,l,s,u){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="client-app-specs-sprint-4-đat-cho-thanh-toan-checkout-ux" tabindex="-1">[Client / App Specs] Sprint 4: Đặt chỗ &amp; Thanh toán (Checkout UX) <a class="header-anchor" href="#client-app-specs-sprint-4-đat-cho-thanh-toan-checkout-ux" aria-label="Permalink to &quot;[Client / App Specs] Sprint 4: Đặt chỗ &amp; Thanh toán (Checkout UX)&quot;">​</a></h1><p>Đặc tả chi tiết giao diện và hiển thị quy trình đặt chỗ dành cho Khách hàng trên Web/App.</p><h2 id="_1-man-hinh-chi-tiet-tour-pre-checkout" tabindex="-1">1. Màn hình Chi tiết Tour (Pre-Checkout) <a class="header-anchor" href="#_1-man-hinh-chi-tiet-tour-pre-checkout" aria-label="Permalink to &quot;1. Màn hình Chi tiết Tour (Pre-Checkout)&quot;">​</a></h2><ul><li><strong>Web Client</strong>: <ul><li><strong>UI</strong>: Panel bên trái hiển thị ảnh, chính giữa là content, panel bên phải (Sticky) là Form chọn ngày &amp; đặt chỗ.</li><li><strong>Interaction</strong>: Khi chọn ngày (Calendar) -&gt; Hệ thống tự động fetch và hiển thị số lượng người còn được phép đặt (Remaining slots).</li></ul></li><li><strong>Mobile App</strong>: <ul><li><strong>UI</strong>: Nút &quot;Đặt ngay&quot; (Blue primary) dính dưới cùng màn hình (Sticky Footer). Khi click -&gt; Mở trang Checkout.</li></ul></li></ul><h2 id="_2-quy-trinh-thanh-toan-3-buoc-3-step-checkout-ux" tabindex="-1">2. Quy trình Thanh toán 3 Bước (3-Step Checkout UX) <a class="header-anchor" href="#_2-quy-trinh-thanh-toan-3-buoc-3-step-checkout-ux" aria-label="Permalink to &quot;2. Quy trình Thanh toán 3 Bước (3-Step Checkout UX)&quot;">​</a></h2><ul><li><strong>Bước 1 (Thông tin)</strong>: <ul><li><strong>Header</strong>: Thanh tiến trình (Step Indicator) dán phía trên.</li><li><strong>Form</strong>: <code>Input</code> thông tin liên hệ, SĐT, Email (Sử dụng regex validate).</li><li><strong>Component</strong>: Chọn số lượng Người lớn (Adults), Trẻ em (Children).</li></ul></li><li><strong>Bước 2 (Thanh toán)</strong>: <ul><li><strong>UI</strong>: Danh sách <code>RadioList</code> chọn Phương thức thanh toán (MoMo, VNPay, Chuyển khoản).</li><li><strong>Summary Card</strong>: Hiển thị chiết khấu từ Voucher, Phí dịch vụ (nếu có), Tổng cộng.</li></ul></li><li><strong>Bước 3 (Kết quả)</strong>: <ul><li><strong>Màn hình thành công</strong>: Ảnh minh họa &quot;Happy Party&quot;, Mã đơn hàng (Booking ID), Mã QR đơn hàng.</li><li><strong>Màn hình thất bại</strong>: Thông điệp lỗi chi tiết (e.g. &quot;Số dư thẻ không đủ&quot;), Nút &quot;Thử lại thanh toán&quot;.</li></ul></li></ul><h2 id="_3-quan-ly-đon-hang-cua-toi-my-bookings-ui" tabindex="-1">3. Quản lý Đơn hàng của Tôi (My Bookings UI) <a class="header-anchor" href="#_3-quan-ly-đon-hang-cua-toi-my-bookings-ui" aria-label="Permalink to &quot;3. Quản lý Đơn hàng của Tôi (My Bookings UI)&quot;">​</a></h2><ul><li><strong>Web Client (Profile)</strong>: Danh sách các đơn đã đặt, cho phép click xem chi tiết vé điện tử (E-Voucher).</li><li><strong>Mobile App (Tab Bookings)</strong>: <ul><li>Hiển thị theo dạng Card ngang. Có tab lọc Trạng thái.</li><li>Thông báo đẩy (Push notification) khi đơn hàng chuyển từ <code>PENDING</code> sang <code>PAID</code>.</li></ul></li></ul><h2 id="_4-đac-ta-bien-nhan-receipt-e-voucher" tabindex="-1">4. Đặc tả Biên nhận (Receipt &amp; E-Voucher) <a class="header-anchor" href="#_4-đac-ta-bien-nhan-receipt-e-voucher" aria-label="Permalink to &quot;4. Đặc tả Biên nhận (Receipt &amp; E-Voucher)&quot;">​</a></h2><ul><li><strong>E-Voucher</strong>: Chứa mã QR định danh đơn hàng để nhân viên soát vé tại điểm khởi hành (Web dashboard check).</li></ul><hr><p><em>Tài liệu đặc tả Client/App cho Sprint 4.</em></p>',12)])])}const d=t(a,[["render",e]]);export{g as __pageData,d as default};
